#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <limits.h>
#include <math.h>
#include <unistd.h>
#include <fcntl.h>
#include <float.h>
#include <time.h>
#include <sys/time.h>
#include <omp.h>

#define BLOCK_X 16
#define BLOCK_Y 16
#define PI 3.1415926535897932
#define SCALE_FACTOR 300.0f

int threads_per_block = 512;

long M = INT_MAX;
int A = 1103515245;
int C = 12345;

int device_id_inuse = 0;
int platform_id_inuse = 0;

#ifndef FLT_MAX
#define FLT_MAX 3.40282347e+38
#endif

long long get_time() {
    struct timeval tv;
    gettimeofday(&tv, NULL);
    return (tv.tv_sec * 1000000) + tv.tv_usec;
}

float elapsed_time(long long start_time, long long end_time) {
    return (float)(end_time - start_time) / (1000 * 1000);
}

float randu(int *seed, int index) {
    int num = A * seed[index] + C;
    seed[index] = num % M;
    return fabs(seed[index] / ((float)M));
}

float randn(int *seed, int index) {
    float u = randu(seed, index);
    float v = randu(seed, index);
    float cosine = cosf(2.0f * (float)PI * v);
    float rt = -2.0f * logf(u);
    return sqrtf(rt) * cosine;
}

float roundFloat(float value) {
    int newValue = (int)(value);
    if (value - newValue < .5f)
        return newValue;
    else
        return newValue++;
}

void setIf(int testValue, int newValue, unsigned char *array3D, int *dimX, int *dimY, int *dimZ) {
    int x, y, z;
    #pragma omp parallel for collapse(3) private(x,y,z)
    for (x = 0; x < *dimX; x++) {
        for (y = 0; y < *dimY; y++) {
            for (z = 0; z < *dimZ; z++) {
                if (array3D[x * *dimY * *dimZ + y * *dimZ + z] == testValue)
                    array3D[x * *dimY * *dimZ + y * *dimZ + z] = newValue;
            }
        }
    }
}

void addNoise(unsigned char *array3D, int *dimX, int *dimY, int *dimZ, int *seed) {
    int x, y, z;
    for (x = 0; x < *dimX; x++) {
        for (y = 0; y < *dimY; y++) {
            for (z = 0; z < *dimZ; z++) {
                array3D[x * *dimY * *dimZ + y * *dimZ + z] =
                    array3D[x * *dimY * *dimZ + y * *dimZ + z] + (unsigned char)(5 * randn(seed, 0));
            }
        }
    }
}

void strelDisk(int *disk, int radius) {
    int diameter = radius * 2 - 1;
    int x, y;
    #pragma omp parallel for collapse(2) private(x,y)
    for (x = 0; x < diameter; x++) {
        for (y = 0; y < diameter; y++) {
            float distance = sqrtf(powf((float)(x - radius + 1), 2) + powf((float)(y - radius + 1), 2));
            if (distance < radius)
                disk[x * diameter + y] = 1;
            else
                disk[x * diameter + y] = 0;
        }
    }
}

void dilate_matrix(unsigned char *matrix, int posX, int posY, int posZ, int dimX, int dimY, int dimZ, int error) {
    int startX = posX - error;
    while (startX < 0) startX++;
    int startY = posY - error;
    while (startY < 0) startY++;
    int endX = posX + error;
    while (endX > dimX) endX--;
    int endY = posY + error;
    while (endY > dimY) endY--;

    int x, y;
    for (x = startX; x < endX; x++) {
        for (y = startY; y < endY; y++) {
            float distance = sqrtf(powf((float)(x - posX), 2) + powf((float)(y - posY), 2));
            if (distance < error)
                matrix[x * dimY * dimZ + y * dimZ + posZ] = 1;
        }
    }
}

void imdilate_disk(unsigned char *matrix, int dimX, int dimY, int dimZ, int error, unsigned char *newMatrix) {
    int x, y, z;
    for (z = 0; z < dimZ; z++) {
        for (x = 0; x < dimX; x++) {
            for (y = 0; y < dimY; y++) {
                if (matrix[x * dimY * dimZ + y * dimZ + z] == 1) {
                    dilate_matrix(newMatrix, x, y, z, dimX, dimY, dimZ, error);
                }
            }
        }
    }
}

void getneighbors(int *se, int numOnes, int *neighbors, int radius) {
    int x, y;
    int neighY = 0;
    int center = radius - 1;
    int diameter = radius * 2 - 1;
    for (x = 0; x < diameter; x++) {
        for (y = 0; y < diameter; y++) {
            if (se[x * diameter + y]) {
                neighbors[neighY * 2] = (int)(y - center);
                neighbors[neighY * 2 + 1] = (int)(x - center);
                neighY++;
            }
        }
    }
    (void)numOnes;
}

void videoSequence(unsigned char *I, int IszX, int IszY, int Nfr, int *seed) {
    int k;
    int max_size = IszX * IszY * Nfr;

    int x0 = (int)roundFloat(IszY / 2.0f);
    int y0 = (int)roundFloat(IszX / 2.0f);
    I[x0 * IszY * Nfr + y0 * Nfr + 0] = 1;

    int xk, yk, pos;
    for (k = 1; k < Nfr; k++) {
        xk = abs(x0 + (k - 1));
        yk = abs(y0 - 2 * (k - 1));
        pos = yk * IszY * Nfr + xk * Nfr + k;
        if (pos >= max_size) pos = 0;
        I[pos] = 1;
    }

    unsigned char *newMatrix = (unsigned char *)calloc(IszX * IszY * Nfr, sizeof(unsigned char));
    imdilate_disk(I, IszX, IszY, Nfr, 5, newMatrix);

    int x, y;
    #pragma omp parallel for collapse(3) private(x,y,k)
    for (x = 0; x < IszX; x++) {
        for (y = 0; y < IszY; y++) {
            for (k = 0; k < Nfr; k++) {
                I[x * IszY * Nfr + y * Nfr + k] = newMatrix[x * IszY * Nfr + y * Nfr + k];
            }
        }
    }
    free(newMatrix);

    setIf(0, 100, I, &IszX, &IszY, &Nfr);
    setIf(1, 228, I, &IszX, &IszY, &Nfr);

    addNoise(I, &IszX, &IszY, &Nfr, seed);
}

float calcLikelihoodSum(unsigned char *I, int *ind, int numOnes, int index) {
    float likelihoodSum = 0.0f;
    int y;
    int base = index * numOnes;
    for (y = 0; y < numOnes; y++) {
        likelihoodSum += (powf((float)(I[ind[base + y]] - 100), 2) -
                          powf((float)(I[ind[base + y]] - 228), 2)) / 50.0f;
    }
    return likelihoodSum;
}

void cdfCalc(float *CDF, float *weights, int Nparticles) {
    int x;
    CDF[0] = weights[0];
    for (x = 1; x < Nparticles; x++) {
        CDF[x] = weights[x] + CDF[x - 1];
    }
}

void likelihood_kernel_omp(float *arrayX, float *arrayY, float *xj, float *yj,
                           int *ind, int *objxy, float *likelihood, unsigned char *I,
                           float *weights, int Nparticles, int countOnes, int max_size,
                           int k, int IszY, int Nfr, int *seed,
                           float *partial_sums, int num_blocks) {
    int i, y;
    for (i = 0; i < num_blocks; i++) partial_sums[i] = 0.0f;

    #pragma omp parallel for private(i,y)
    for (i = 0; i < Nparticles; i++) {
        arrayX[i] = xj[i];
        arrayY[i] = yj[i];
        weights[i] = 1.0f / ((float)Nparticles);

        arrayX[i] = arrayX[i] + 1.0f + 5.0f * randn(seed, i);
        arrayY[i] = arrayY[i] - 2.0f + 2.0f * randn(seed, i);

        for (y = 0; y < countOnes; y++) {
            int indX = (int)roundFloat(arrayX[i]) + objxy[y * 2 + 1];
            int indY = (int)roundFloat(arrayY[i]) + objxy[y * 2];
            int idx = abs(indX * IszY * Nfr + indY * Nfr + k);
            if (idx >= max_size) idx = 0;
            ind[i * countOnes + y] = idx;
        }

        likelihood[i] = calcLikelihoodSum(I, ind, countOnes, i);
        likelihood[i] = likelihood[i] / countOnes - SCALE_FACTOR;
        weights[i] = weights[i] * expf(likelihood[i]);

        int block_id = i / threads_per_block;
        #pragma omp atomic
        partial_sums[block_id] += weights[i];
    }
}

void sum_kernel_omp(float *partial_sums, int Nparticles) {
    int num_blocks = (int)ceil((float)Nparticles / (float)threads_per_block);
    float sum = 0.0f;
    int x;
    for (x = 0; x < num_blocks; x++) sum += partial_sums[x];
    partial_sums[0] = sum;
}

void normalize_weights_kernel_omp(float *weights, int Nparticles, float *partial_sums,
                                  float *CDF, float *u, int *seed) {
    float sumWeights = partial_sums[0];

    #pragma omp parallel for
    for (int i = 0; i < Nparticles; i++) {
        weights[i] = weights[i] / sumWeights;
    }

    cdfCalc(CDF, weights, Nparticles);
    u[0] = (1.0f / ((float)Nparticles)) * randu(seed, 0);

    float u1 = u[0];
    #pragma omp parallel for
    for (int i = 0; i < Nparticles; i++) {
        u[i] = u1 + i / ((float)Nparticles);
    }
}

void find_index_kernel_omp(float *arrayX, float *arrayY, float *CDF, float *u,
                           float *xj, float *yj, int Nparticles) {
    #pragma omp parallel for
    for (int i = 0; i < Nparticles; i++) {
        int index = -1;
        for (int x = 0; x < Nparticles; x++) {
            if (CDF[x] >= u[i]) {
                index = x;
                break;
            }
        }
        if (index == -1) index = Nparticles - 1;
        xj[i] = arrayX[index];
        yj[i] = arrayY[index];
    }
}

int particleFilter(unsigned char *I, int IszX, int IszY, int Nfr, int *seed, int Nparticles) {
    int max_size = IszX * IszY * Nfr;

    float xe = roundFloat(IszY / 2.0f);
    float ye = roundFloat(IszX / 2.0f);

    int radius = 5;
    int diameter = radius * 2 - 1;
    int *disk = (int *)calloc(diameter * diameter, sizeof(int));
    strelDisk(disk, radius);

    int countOnes = 0;
    for (int x = 0; x < diameter; x++) {
        for (int y = 0; y < diameter; y++) {
            if (disk[x * diameter + y] == 1) countOnes++;
        }
    }

    int *objxy = (int *)calloc(countOnes * 2, sizeof(int));
    getneighbors(disk, countOnes, objxy, radius);

    float *weights = (float *)calloc(Nparticles, sizeof(float));
    for (int x = 0; x < Nparticles; x++) {
        weights[x] = 1.0f / ((float)Nparticles);
    }

    float *likelihood = (float *)calloc(Nparticles + 1, sizeof(float));
    float *arrayX = (float *)calloc(Nparticles, sizeof(float));
    float *arrayY = (float *)calloc(Nparticles, sizeof(float));
    float *xj = (float *)calloc(Nparticles, sizeof(float));
    float *yj = (float *)calloc(Nparticles, sizeof(float));
    float *CDF = (float *)calloc(Nparticles, sizeof(float));
    int *ind = (int *)calloc((size_t)countOnes * (size_t)Nparticles, sizeof(int));
    float *u = (float *)calloc(Nparticles, sizeof(float));

    int num_blocks = (int)ceil((float)Nparticles / (float)threads_per_block);
    float *partial_sums = (float *)calloc(num_blocks + 1, sizeof(float));

    for (int x = 0; x < Nparticles; x++) {
        xj[x] = xe;
        yj[x] = ye;
    }

    long long send_start = get_time();
    long long send_end = get_time();
    printf("TIME TO SEND TO GPU: %f\n", elapsed_time(send_start, send_end));
    printf("threads_per_block=%d \n", threads_per_block);

    for (int k = 1; k < Nfr; k++) {
        likelihood_kernel_omp(arrayX, arrayY, xj, yj, ind, objxy, likelihood, I, weights,
                              Nparticles, countOnes, max_size, k, IszY, Nfr, seed,
                              partial_sums, num_blocks);

        sum_kernel_omp(partial_sums, Nparticles);

        normalize_weights_kernel_omp(weights, Nparticles, partial_sums, CDF, u, seed);

        xe = 0.0f;
        ye = 0.0f;
        float total = 0.0f;
        for (int x = 0; x < Nparticles; x++) {
            xe = xe + (arrayX[x] * weights[x]);
            ye = ye + (arrayY[x] * weights[x]);
            total += weights[x];
        }

        printf("total weight: %lf\n", total);
        printf("XE: %lf\n", xe);
        printf("YE: %lf\n", ye);
        float distance = sqrtf(powf((float)(xe - (int)roundFloat(IszY / 2.0f)), 2) +
                               powf((float)(ye - (int)roundFloat(IszX / 2.0f)), 2));
        printf("%lf\n", distance);

        find_index_kernel_omp(arrayX, arrayY, CDF, u, xj, yj, Nparticles);
    }

    long long back_time = get_time();
    long long free_time = get_time();
    long long arrayX_time = get_time();
    long long arrayY_time = get_time();
    long long back_end_time = get_time();

    printf("GPU Execution: %lf\n", elapsed_time(send_end, back_time));
    printf("FREE TIME: %lf\n", elapsed_time(back_time, free_time));
    printf("SEND TO SEND BACK: %lf\n", elapsed_time(back_time, back_end_time));
    printf("SEND ARRAY X BACK: %lf\n", elapsed_time(free_time, arrayX_time));
    printf("SEND ARRAY Y BACK: %lf\n", elapsed_time(arrayX_time, arrayY_time));
    printf("SEND WEIGHTS BACK: %lf\n", elapsed_time(arrayY_time, back_end_time));

    xe = 0.0f;
    ye = 0.0f;
    for (int x = 0; x < Nparticles; x++) {
        xe += arrayX[x] * weights[x];
        ye += arrayY[x] * weights[x];
    }
    float distance = sqrtf(powf((float)(xe - (int)roundFloat(IszY / 2.0f)), 2) +
                           powf((float)(ye - (int)roundFloat(IszX / 2.0f)), 2));

    FILE *fid;
    fid = fopen("output.txt", "w+");
    if (fid == NULL) {
        printf("The file was not opened for writing\n");
        return -1;
    }
    fprintf(fid, "XE: %lf\n", xe);
    fprintf(fid, "YE: %lf\n", ye);
    fprintf(fid, "distance: %lf\n", distance);
    fclose(fid);

    free(likelihood);
    free(arrayX);
    free(arrayY);
    free(xj);
    free(yj);
    free(CDF);
    free(ind);
    free(u);
    free(partial_sums);
    free(weights);
    free(objxy);
    free(disk);

    return 0;
}

int main(int argc, char *argv[]) {
    const char *usage = "float.out -x <dimX> -y <dimY> -z <Nfr> -np <Nparticles> [-p platform] [-d device]";

    if (argc < 9) {
        printf("%s\n", usage);
        return 0;
    }

    if (strcmp(argv[1], "-x") || strcmp(argv[3], "-y") || strcmp(argv[5], "-z") || strcmp(argv[7], "-np")) {
        printf("%s\n", usage);
        return 0;
    }

    int IszX, IszY, Nfr, Nparticles;

    if (sscanf(argv[2], "%d", &IszX) == EOF) {
        printf("ERROR: dimX input is incorrect");
        return 0;
    }
    if (IszX <= 0) {
        printf("dimX must be > 0\n");
        return 0;
    }

    if (sscanf(argv[4], "%d", &IszY) == EOF) {
        printf("ERROR: dimY input is incorrect");
        return 0;
    }
    if (IszY <= 0) {
        printf("dimY must be > 0\n");
        return 0;
    }

    if (sscanf(argv[6], "%d", &Nfr) == EOF) {
        printf("ERROR: Number of frames input is incorrect");
        return 0;
    }
    if (Nfr <= 0) {
        printf("number of frames must be > 0\n");
        return 0;
    }

    if (sscanf(argv[8], "%d", &Nparticles) == EOF) {
        printf("ERROR: Number of particles input is incorrect");
        return 0;
    }
    if (Nparticles <= 0) {
        printf("Number of particles must be > 0\n");
        return 0;
    }

    for (int i = 9; i < argc; ++i) {
        switch (argv[i][1]) {
            case 'p':
                if (++i < argc) sscanf(argv[i], "%d", &platform_id_inuse);
                break;
            case 'd':
                if (++i < argc) sscanf(argv[i], "%d", &device_id_inuse);
                break;
            default:
                break;
        }
    }

    int *seed = (int *)calloc(Nparticles, sizeof(int));
    for (int i = 0; i < Nparticles; i++) seed[i] = i + 1;

    unsigned char *I = (unsigned char *)calloc(IszX * IszY * Nfr, sizeof(unsigned char));

    long long start = get_time();
    videoSequence(I, IszX, IszY, Nfr, seed);
    long long endVideoSequence = get_time();
    printf("VIDEO SEQUENCE TOOK %f\n", elapsed_time(start, endVideoSequence));

    particleFilter(I, IszX, IszY, Nfr, seed, Nparticles);
    long long endParticleFilter = get_time();
    printf("PARTICLE FILTER TOOK %f\n", elapsed_time(endVideoSequence, endParticleFilter));
    printf("ENTIRE PROGRAM TOOK %f\n", elapsed_time(start, endParticleFilter));

    free(seed);
    free(I);
    return 0;
}
